def sum_integers_in_list(mixed_list):
    total = 0
    for item in mixed_list:
        try:
            total += int(item)
        except ValueError:
            pass
    return total

if __name__ == "__main__":
    input_data = input().split()
    result = sum_integers_in_list(input_data)
    print(result)
